                <th
                  scope="col"
                  className="px-4 py-3 text-start font-medium text-muted-foreground"
                >
                  كود الفاتورة
                </th>
                <th
                  scope="col"
                  className="px-4 py-3 text-start font-medium text-muted-foreground"
                >
                  العميل
