                  <td className="px-4 py-3 font-mono text-xs text-primary">
                    {invoice.invoiceCode}
                  </td>
                  <td className="px-4 py-3 font-medium">
                    {invoice.client.name}
                  </td>
                  <td className="px-4 py-3 font-mono">
                    {formatNumber(invoice.total)}
